#!/usr/bin/env node

const path = require("path");

console.log("Running setup.js");
// Resolve the correct path to index.js
const projectRoot = path.resolve(__dirname, "..");
const { generateAllTypes } = require(path.join(projectRoot, "index.js"));
// Get user-provided template path from CLI args
const templatePath = process.argv[2];
console.log("argv: ", process.argv);
if (!templatePath) {
  console.error("Usage: latex-to-pdf generate-types <TEMPLATE_PATH>");
  process.exit(1);
}

// Generate type definitions
const names=generateAllTypes(templatePath);
console.log("Type definitions generated successfully.", names);
